INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("お！\nあそこに困ってそうな人発見！", "ねぇねぇ、騎士クン\n手伝ってあげようよ～", 1001, 0, 1.4, "春咲 ひより", 0, 0, "ヒヨリでっす♪\n元気いっぱいがんばるよ♪", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("大切な人を\n守れるようになりたい…って", "わ、わたし、\nなに言ってるんだろ\nあはは…", 1002, 0, 1.4, "草野 優衣", 0, 0, "みんなみたいに\nわたしも強くならなきゃ", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("キミに必要な集中力と感性が", "少しは磨かれると思いますよ。", 1003, 0, 1.4, "士条 怜", 0, 0, "フェンシングを始めてみては？", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("今日はなにして遊ぶ？", "みそぎはねぇ、\nかくれんぼやりたい！", 1004, 0, 1.5, "穂高 みそぎ", 0, 0, "ねぇ、にいちゃん！", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ねぇ…", "私といっしょに…\nいかない？", 1006, 0, 1.4, "風宮 あかり", 0, 0, "風宮あかりです", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("プリンたべたいのー", "食べ物の恨みは怖いのー", 1007, 0, 1.5, "出雲 宮子", 0, 0, "出雲宮子なのー", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("キミもボクの美貌に\n吸い寄せられたんだね。", "いいよ。\n見られることは運命さ…", 1008, 0, 1.4, "虹村 雪", 0, 0, "ボクは虹村雪。", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("我が真名は\nアンネローゼ・フォン・シュテッヒパルム！", "人呼んで「疾風の冥姫」!!", 1009, 0, 1.4, "柊杏奈", 0, 0, "フッ…聞いて後悔するがいい！", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("うさぎさん、\n運命の王子はんに巡りあわせてくれて", "ほんまおおきにやわ～♪", 1010, 0, 1.5, "姫宮 真歩", 0, 0, "マホマホ王国のプリンセス、\nまほ姫どす", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("生き別れたお兄ちゃんを探して\n三千世界！", "ここで会ったが\n100年目～！", 1011, 0, 1.4, "衣之咲 璃乃", 0, 0, "衣之咲璃乃です！", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ち、超能力って…\n何のことかな～？", "…って、お願い！\n誰にも言わないでおいて～！", 1012, 0, 1.4, "柏崎 初音", 0, 0, "私はハツネ、\n結構強いんだよ。\nきらーん☆", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("一応カリスマ読モJKやってまっす！", "ヒデサイまぢ\nGF（グッドフィーリング）～♪", 1016, 0, 1.4, "美波 鈴奈", 0, 0, "ちょす！\n美波鈴奈だよ～♪", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("東京は遊園地みたいなところさー", "でも、沖縄もとってもいいとこさー", 1017, 0, 1.4, "喜屋武 香織", 0, 0, "はいたーい。\n喜屋武香織さー。", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("先生って呼ばれるのは\nくすぐったいから", "イオちゃんって呼んでね。", 1018, 0, 1.4, "支倉 伊緒", 0, 0, "支倉伊緒です。", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("あ！/\お兄ちゃ～ん\nまってよ～", "ミミをおいてかないでぇ～", 1020, 0, 1.5, "茜 ミミ", 0, 0, "ふえ…？\nミミ、むずかしいこと\nよくわかんない…", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("あの……\nふぇ……", "ふぇぇぇぇぇん……", 1021, 0, 1.5, "栗林 くるみ", 0, 0, "あ…あの…えっと…\n栗…林…くるみ…です……", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("こんな私に貴重な時間を\n割いていただき、", "なんてありがとうございます！", 1022, 0, 1.4, "風宮 より", 0, 0, "風宮よりです。\nあああああ！", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("おにいちゃんどこいくの？\nえ？", "私こっち行きたいー\nね、早く早くー", 1023, 0, 1.5, "北条 綾音", 0, 0, "私、アヤネ！\nぷうきちと一緒についてってあげるね！", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ふ、不束者ですが\nどうぞ末永く…って、", "これて何か違う…\nあああすみません！", 1025, 0, 1.4, "天野 すずめ", 0, 0, "わっ…わっ…私、\n天野すずめといいます！", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("あなたは…運命の……\n伴侶……", "離しませんわ………\n絶対に…!!", 1027, 0, 1.4, "倉石 恵理子", 0, 0, "……クスクス…私は\n…倉石恵理子……", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！", "…そうでしょ？？", 1028, 0, 1.4, "佐々木 咲恋", 0, 0, "佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ぇっと…\nキミ、私のこと知らないの?!", "あはは、\n私もまだまだだなぁ～", 1029, 0, 1.4, "桜井 望", 0, 0, "桜井望だよ！\nよろしくねっ", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("初めまして、\n私はニノン・ジュベール申すデス！", "ショーグン、\nワタシと一緒に天下統一デース！", 1030, 0, 1.4, "ニノン・ジュベール", 0, 0, "デケデケデンっ！", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("でもって私の隣にいるのが……\nえ、見えない？", "おかしいですね……", 1031, 0, 1.4, "上喜 しのぶ", 0, 0, "上喜しのぶです。\n手元のドクロが父です。", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("けんども\nそれには足りないモンが…", "そう、\nオラのボケに突っ込める相方が…！", 1033, 0, 1.5, "野戸まひる", 0, 0, "目指すはビッグな\nお笑い芸人だっぺ！", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ちょっと緊張しちゃって…", "ちょ\nちょっと一杯飲んできます…！", 1034, 0, 1.4, "綾瀬 ゆかり", 0, 0, "あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("知らない人とは話しちゃいけないので", "これ以上お話しすることは…\nないです！", 1036, 0, 1.5, "氷川 鏡華", 0, 0, "氷川鏡華…です", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("……あ、アラーム。", "私体が弱いから、\n30分に一度休憩しないと\nいけないんです。", 1038, 0, 1.4, "柏崎 栞", 0, 0, "柏崎…栞です。", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("私、一人も友達がいなくて……", "野に咲く花が、\n唯一の話相手です。", 1040, 0, 1.4, "双葉 碧", 0, 0, "ふ、双葉碧です。", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("私の歌声で、\n皆さんが幸せになってくれたらいいなって…", "そう思っています。", 1042, 0, 1.4, "三角 千歌", 0, 0, "三角千歌です。", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("あぁ？\nお前のそいつの仲間か？", "う、疑ってすまなかったな…", 1043, 0, 1.4, "安芸 真琴", 0, 0, "安芸真琴だ。", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("生けとし生ける全ての者よ！", "わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！", 1044, 0, 1.4, "イリヤ・オーンスタイン", 0, 0, "わらわこそは夜を総べる者！", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ぐふふふふ……はっ！", "ｌク、クウカに何かご用ですか!?", 1045, 0, 1.4, "遠見 空花", 0, 0, "そこで騎士は妖精を乱暴に……", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("自由気ままで♪\n寝て遊んで、食べてケンカして…", "う～ん…\n猫ってホントに最高にゃ～♪", 1046, 0, 1.4, "宮坂たまき", 0, 0, "宮坂たまきにゃ♪\n猫はいいにゃよ？", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("それでは早速クエストに…", "…と思ったら\nバイトの時間だ！\nまたあとでね！", 1048, 0, 1.4, "大神 美冬", 0, 0, "大神美冬よ！", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("クエストもバトルも\n掃除も洗濯も", "お姉ちゃんがぜ～んぶ\nやってあげるからね！", 1049, 0, 1.4, "星野静流", 0, 0, "星野静流だよ！", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("見ての通りの\nセクシー美少女で", "学校では誰もが憧れる\nアイドル的な存在ってやつよ♪", 1050, 0, 1.5, "玉泉美咲", 0, 0, "アタシは玉泉美咲。", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("？？？？", "？？？？", 1052, 0, 1.4, "リマ", 0, 0, "？？？", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("菓子でつろうなどと\n稚拙な策を……", "そ、そこまでいうなら\nもらってやる", 1053, 0, 1.5, "モニカ・ヴァイスヴィント", 0, 0, "モニカ・ヴァイスヴィントだ。", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("菓子でつろうなどと\n稚拙な策を……", "そ、そこまでいうなら\nもらってやる", 1058, 0, 1.5, "ペコリーヌ", 0, 0, "モニカ・ヴァイスヴィントだ。", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("菓子でつろうなどと\n稚拙な策を……", "そ、そこまでいうなら\nもらってやる", 1059, 0, 1.5, "コッコロ", 0, 0, "モニカ・ヴァイスヴィントだ。", 0, 2, 1, 1, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("菓子でつろうなどと\n稚拙な策を……", "そ、そこまでいうなら\nもらってやる", 1060, 0, 1.5, "キャル", 0, 0, "モニカ・ヴァイスヴィントだ。", 0, 2, 1, 1, 0, 1);
